 6→namespace CodexLib.Common
 7→{
 8→    using System;
 9→    using System.Reflection;
10→    using System.Text.Json;
11→
12→    /// <summary>
13→    /// JsonSerializerExt.
14→    /// </summary>.
15→    internal class JsonSerializerExt
16→    {
17→        /// <summary>
18→        /// RawJsonContentPropertyName.
19→        /// </summary>
20→        private const string RawJsonContentPropertyName = "RawJsonContent";
21→
22→        /// <summary>
23→        /// Deserialize with Raw Json Content.
24→        /// </summary>
25→        /// <typeparam name="T">T.</typeparam>
26→        /// <param name="jsonContent">jsonContent.</param>
27→        /// <returns>obj.</returns>
28→        public static T DeserializeWithRawJsonContent<T>(string jsonContent)
29→        {
30→            var obj = JsonSerializer.Deserialize<T>(jsonContent);
31→            var rawJsonContentProperty = GetInnerRawContentProperty(typeof(T));
32→            if (rawJsonContentProperty != null)
33→            {
34→                rawJsonContentProperty.SetValue(obj, jsonContent);
35→            }
36→
37→            return obj;
38→        }
39→
40→        /// <summary>
41→        /// GetInnerRawContentProperty.
42→        /// </summary>
43→        /// <param name="type">type.</param>
44→        /// <returns>property info.</returns>
45→        private static PropertyInfo GetInnerRawContentProperty(Type type)
46→        {
47→            var property = type.GetProperty(RawJsonContentPropertyName, System.Reflection.BindingFlags.SetProperty | System.Reflection.BindingFlags.GetProperty | System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance);
48→            if (property != null && property.PropertyType == typeof(string))
49→            {
50→                return property;
51→            }
52→
53→            return null;
54→        }
55→    }
56→}
